 23→/**
 24→ * Integration tests for M3 Task State Machine — Status Transition Endpoints.
 25→ *
 26→ * Covers all 16 acceptance criteria (AC1-AC16) from M3-task-state-machine spec.
 27→ * Uses full Spring Boot context with MockMvc to test through security filter chain.
 28→ *
 29→ * New endpoints under test:
 30→ *   PATCH /api/tasks/{id}/status  — execute a state transition
 31→ *   GET   /api/tasks/{id}/transitions — query available transitions
 32→ *
 33→ * Tests will FAIL until TaskService.transitionStatus(), TaskService.getAvailableTransitions(),
 34→ * StatusTransitionRequest, TransitionsResponse, InvalidTransitionException,
 35→ * and new controller endpoints are implemented.
 36→ */
 37→@SpringBootTest
 38→@AutoConfigureMockMvc
 39→@DisplayName("Task Status Transition Integration Tests (M3 State Machine)")
 40→class TaskStatusTransitionIntegrationTest {
 41→
 42→    @Autowired
 43→    private MockMvc mockMvc;
 44→
 45→    @Autowired
 46→    private ObjectMapper objectMapper;
 47→
 48→    @Autowired
 49→    private JwtTokenProvider jwtTokenProvider;
 50→
 51→    @Autowired
 52→    private UserRepository userRepository;
 53→
 54→    @Autowired
 55→    private TaskRepository taskRepository;
 56→
 57→    private String authToken;
 58→    private Long testUserId;
 59→
 60→    @BeforeEach
 61→    void setUp() {
 62→        taskRepository.deleteAll();
 63→        userRepository.deleteAll();
 64→
 65→        User user = new User();
 66→        user.setUsername("testuser");
 67→        user.setPassword("encoded_password");
 68→        user.setDisplayName("Test User");
 69→        user = userRepository.save(user);
 70→        testUserId = user.getId();
 71→
 72→        authToken = jwtTokenProvider.generateToken(testUserId);
 73→    }
 74→
 75→    // ── Helper methods ──────────────────────────────────────────────────
 76→
 77→    /**
 78→     * Creates a task via POST /api/tasks and returns the response as JsonNode.
 79→     */
 80→    private JsonNode createTaskViaApi(String title) throws Exception {
 81→        String body = "{\"title\":\"" + title + "\",\"description\":\"Test description\",\"priority\":\"MEDIUM\"}";
 82→        MvcResult result = mockMvc.perform(post("/api/tasks")
 83→                        .header("Authorization", "Bearer " + authToken)
 84→                        .contentType(MediaType.APPLICATION_JSON)
 85→                        .content(body))
 86→                .andExpect(status().isCreated())
 87→                .andReturn();
 88→        return objectMapper.readTree(result.getResponse().getContentAsString());
 89→    }
 90→
 91→    /**
 92→     * Calls PATCH /api/tasks/{id}/status with the given target status.
 93→     * Returns the MvcResult for further assertions.
 94→     */
 95→    private MvcResult transitionStatus(long taskId, String targetStatus) throws Exception {
 96→        String body = "{\"status\":\"" + targetStatus + "\"}";
 97→        return mockMvc.perform(patch("/api/tasks/{id}/status", taskId)
 98→                        .header("Authorization", "Bearer " + authToken)
 99→                        .contentType(MediaType.APPLICATION_JSON)
100→                        .content(body))
101→                .andReturn();
102→    }
103→
104→    /**
105→     * Calls PATCH /api/tasks/{id}/status and expects 200, returning the response as JsonNode.
106→     */
107→    private JsonNode transitionStatusExpect200(long taskId, String targetStatus) throws Exception {
108→        String body = "{\"status\":\"" + targetStatus + "\"}";
109→        MvcResult result = mockMvc.perform(patch("/api/tasks/{id}/status", taskId)
110→                        .header("Authorization", "Bearer " + authToken)
111→                        .contentType(MediaType.APPLICATION_JSON)
112→                        .content(body))
113→                .andExpect(status().isOk())
114→                .andReturn();
115→        return objectMapper.readTree(result.getResponse().getContentAsString());
116→    }
117→
118→    /**
119→     * Calls GET /api/tasks/{id}/transitions and returns the MvcResult.
120→     */
121→    private MvcResult getTransitions(long taskId) throws Exception {
122→        return mockMvc.perform(get("/api/tasks/{id}/transitions", taskId)
123→                        .header("Authorization", "Bearer " + authToken))
124→                .andReturn();
125→    }
