377→        void shouldUpdateUpdatedAtOnSuccessfulTransition() throws Exception {
378→            JsonNode created = createTaskViaApi("Task for AC10");
379→            long taskId = created.get("id").asLong();
380→
381→            // The task may have null updatedAt initially (only createdAt is set on creation)
382→            JsonNode response = transitionStatusExpect200(taskId, "IN_PROGRESS");
