392→        void shouldChangeUpdatedAtOnEachTransition() throws Exception {
393→            JsonNode created = createTaskViaApi("Task for AC10b");
394→            long taskId = created.get("id").asLong();
395→
396→            // Transition 1: TODO -> IN_PROGRESS
397→            JsonNode first = transitionStatusExpect200(taskId, "IN_PROGRESS");
398→            String updatedAt1 = first.get("updatedAt").asText();
399→            assertThat(updatedAt1).isNotEmpty();
400→
401→            // Small pause to ensure different timestamp
