package com.taskflow.controller;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.taskflow.entity.Task;
import com.taskflow.entity.TaskStatus;
import com.taskflow.entity.User;
import com.taskflow.repository.TaskRepository;
import com.taskflow.repository.UserRepository;
import com.taskflow.security.JwtTokenProvider;
import org.junit.jupiter.api.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;

import static org.assertj.core.api.Assertions.assertThat;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

/**
 * Integration tests for M3 Task State Machine — Status Transition Endpoints.
 *
 * Covers all 16 acceptance criteria (AC1-AC16) from M3-task-state-machine spec.
 * Uses full Spring Boot context with MockMvc to test through security filter chain.
 *
 * New endpoints under test:
 *   PATCH /api/tasks/{id}/status  — execute a state transition
 *   GET   /api/tasks/{id}/transitions — query available transitions
 *
 * Tests will FAIL until TaskService.transitionStatus(), TaskService.getAvailableTransitions(),
 * StatusTransitionRequest, TransitionsResponse, InvalidTransitionException,
 * and new controller endpoints are implemented.
 */
@SpringBootTest
@AutoConfigureMockMvc
@DisplayName("Task Status Transition Integration Tests (M3 State Machine)")
class TaskStatusTransitionIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private JwtTokenProvider jwtTokenProvider;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TaskRepository taskRepository;

    private String authToken;
    private Long testUserId;

    @BeforeEach
    void setUp() {
        taskRepository.deleteAll();
        userRepository.deleteAll();

        User user = new User();
        user.setUsername("testuser");
        user.setPassword("encoded_password");
        user.setDisplayName("Test User");
        user = userRepository.save(user);
        testUserId = user.getId();

        authToken = jwtTokenProvider.generateToken(testUserId);
    }

    // ── Helper methods ──────────────────────────────────────────────────

    /**
     * Creates a task via POST /api/tasks and returns the response as JsonNode.
     */
    private JsonNode createTaskViaApi(String title) throws Exception {
        String body = "{\"title\":\"" + title + "\",\"description\":\"Test description\",\"priority\":\"MEDIUM\"}";
        MvcResult result = mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(body))
                .andExpect(status().isCreated())
                .andReturn();
        return objectMapper.readTree(result.getResponse().getContentAsString());
    }

    /**
     * Calls PATCH /api/tasks/{id}/status with the given target status.
     * Returns the MvcResult for further assertions.
     */
    private MvcResult transitionStatus(long taskId, String targetStatus) throws Exception {
        String body = "{\"status\":\"" + targetStatus + "\"}";
        return mockMvc.perform(patch("/api/tasks/{id}/status", taskId)
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(body))
                .andReturn();
    }

    /**
     * Calls PATCH /api/tasks/{id}/status and expects 200, returning the response as JsonNode.
     */
    private JsonNode transitionStatusExpect200(long taskId, String targetStatus) throws Exception {
        String body = "{\"status\":\"" + targetStatus + "\"}";
        MvcResult result = mockMvc.perform(patch("/api/tasks/{id}/status", taskId)
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(body))
                .andExpect(status().isOk())
                .andReturn();
        return objectMapper.readTree(result.getResponse().getContentAsString());
    }

    /**
     * Calls GET /api/tasks/{id}/transitions and returns the MvcResult.
     */
    private MvcResult getTransitions(long taskId) throws Exception {
        return mockMvc.perform(get("/api/tasks/{id}/transitions", taskId)
                        .header("Authorization", "Bearer " + authToken))
                .andReturn();
    }

    // ── AC1: New task initial status is TODO ─────────────────────────────

    @Nested
    @DisplayName("AC1: New task initial status is TODO")
    class AC1_InitialStatus {

        @Test
        @DisplayName("POST /api/tasks creates task with status=TODO")
        void shouldCreateTaskWithTodoStatus() throws Exception {
            JsonNode created = createTaskViaApi("New Task");
            assertThat(created.get("status").asText()).isEqualTo("TODO");
        }
    }

    // ── AC2: PATCH TODO -> IN_PROGRESS -> 200 ──────────────────────────

    @Nested
    @DisplayName("AC2: Transition TODO -> IN_PROGRESS returns 200")
    class AC2_TodoToInProgress {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status with TODO -> IN_PROGRESS returns 200 and updated status")
        void shouldTransitionTodoToInProgress() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC2");
            long taskId = created.get("id").asLong();

            JsonNode response = transitionStatusExpect200(taskId, "IN_PROGRESS");

            assertThat(response.get("id").asLong()).isEqualTo(taskId);
            assertThat(response.get("status").asText()).isEqualTo("IN_PROGRESS");
            assertThat(response.get("title").asText()).isEqualTo("Task for AC2");
        }
    }

    // ── AC3: PATCH IN_PROGRESS -> TODO -> 200 ──────────────────────────

    @Nested
    @DisplayName("AC3: Transition IN_PROGRESS -> TODO returns 200")
    class AC3_InProgressToTodo {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status with IN_PROGRESS -> TODO returns 200 and updated status")
        void shouldTransitionInProgressToTodo() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC3");
            long taskId = created.get("id").asLong();

            // First move to IN_PROGRESS
            transitionStatusExpect200(taskId, "IN_PROGRESS");

            // Then move back to TODO
            JsonNode response = transitionStatusExpect200(taskId, "TODO");

            assertThat(response.get("status").asText()).isEqualTo("TODO");
        }
    }

    // ── AC4: PATCH IN_PROGRESS -> DONE -> 200 ──────────────────────────

    @Nested
    @DisplayName("AC4: Transition IN_PROGRESS -> DONE returns 200")
    class AC4_InProgressToDone {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status with IN_PROGRESS -> DONE returns 200 and updated status")
        void shouldTransitionInProgressToDone() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC4");
            long taskId = created.get("id").asLong();

            // Move to IN_PROGRESS first
            transitionStatusExpect200(taskId, "IN_PROGRESS");

            // Then move to DONE
            JsonNode response = transitionStatusExpect200(taskId, "DONE");

            assertThat(response.get("status").asText()).isEqualTo("DONE");
        }
    }

    // ── AC5: PATCH DONE -> CLOSED -> 200 ────────────────────────────────

    @Nested
    @DisplayName("AC5: Transition DONE -> CLOSED returns 200")
    class AC5_DoneToClosed {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status with DONE -> CLOSED returns 200 and updated status")
        void shouldTransitionDoneToClosed() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC5");
            long taskId = created.get("id").asLong();

            // Chain: TODO -> IN_PROGRESS -> DONE
            transitionStatusExpect200(taskId, "IN_PROGRESS");
            transitionStatusExpect200(taskId, "DONE");

            // Then DONE -> CLOSED
            JsonNode response = transitionStatusExpect200(taskId, "CLOSED");

            assertThat(response.get("status").asText()).isEqualTo("CLOSED");
        }
    }

    // ── AC6: PATCH TODO -> DONE (illegal) -> 400 ───────────────────────

    @Nested
    @DisplayName("AC6: Illegal transition TODO -> DONE returns 400")
    class AC6_TodoToDoneIllegal {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status with TODO -> DONE returns 400 Bad Request")
        void shouldReturn400ForTodoToDone() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC6");
            long taskId = created.get("id").asLong();

            MvcResult result = transitionStatus(taskId, "DONE");

            assertThat(result.getResponse().getStatus()).isEqualTo(400);

            // Verify error message is present
            JsonNode errorResponse = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(errorResponse.has("message")).isTrue();
            assertThat(errorResponse.get("message").asText()).isNotEmpty();
        }
    }

    // ── AC7: PATCH CLOSED -> any (illegal) -> 400 ──────────────────────

    @Nested
    @DisplayName("AC7: Illegal transition from CLOSED to any state returns 400")
    class AC7_ClosedToAnyIllegal {

        @Test
        @DisplayName("PATCH CLOSED -> TODO returns 400")
        void shouldReturn400ForClosedToTodo() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC7a");
            long taskId = created.get("id").asLong();

            // Chain to CLOSED: TODO -> IN_PROGRESS -> DONE -> CLOSED
            transitionStatusExpect200(taskId, "IN_PROGRESS");
            transitionStatusExpect200(taskId, "DONE");
            transitionStatusExpect200(taskId, "CLOSED");

            MvcResult result = transitionStatus(taskId, "TODO");
            assertThat(result.getResponse().getStatus()).isEqualTo(400);
        }

        @Test
        @DisplayName("PATCH CLOSED -> IN_PROGRESS returns 400")
        void shouldReturn400ForClosedToInProgress() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC7b");
            long taskId = created.get("id").asLong();

            transitionStatusExpect200(taskId, "IN_PROGRESS");
            transitionStatusExpect200(taskId, "DONE");
            transitionStatusExpect200(taskId, "CLOSED");

            MvcResult result = transitionStatus(taskId, "IN_PROGRESS");
            assertThat(result.getResponse().getStatus()).isEqualTo(400);
        }

        @Test
        @DisplayName("PATCH CLOSED -> DONE returns 400")
        void shouldReturn400ForClosedToDone() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC7c");
            long taskId = created.get("id").asLong();

            transitionStatusExpect200(taskId, "IN_PROGRESS");
            transitionStatusExpect200(taskId, "DONE");
            transitionStatusExpect200(taskId, "CLOSED");

            MvcResult result = transitionStatus(taskId, "DONE");
            assertThat(result.getResponse().getStatus()).isEqualTo(400);
        }

        @Test
        @DisplayName("PATCH CLOSED -> CLOSED (self-transition) returns 400")
        void shouldReturn400ForClosedToClosed() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC7d");
            long taskId = created.get("id").asLong();

            transitionStatusExpect200(taskId, "IN_PROGRESS");
            transitionStatusExpect200(taskId, "DONE");
            transitionStatusExpect200(taskId, "CLOSED");

            MvcResult result = transitionStatus(taskId, "CLOSED");
            assertThat(result.getResponse().getStatus()).isEqualTo(400);
        }
    }

    // ── AC8: PATCH TODO -> CLOSED (illegal) -> 400 ─────────────────────

    @Nested
    @DisplayName("AC8: Illegal transition TODO -> CLOSED returns 400")
    class AC8_TodoToClosedIllegal {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status with TODO -> CLOSED returns 400 Bad Request")
        void shouldReturn400ForTodoToClosed() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC8");
            long taskId = created.get("id").asLong();

            MvcResult result = transitionStatus(taskId, "CLOSED");

            assertThat(result.getResponse().getStatus()).isEqualTo(400);
        }
    }

    // ── AC9: PATCH DONE -> TODO (illegal) -> 400 ───────────────────────

    @Nested
    @DisplayName("AC9: Illegal transition DONE -> TODO returns 400")
    class AC9_DoneToTodoIllegal {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status with DONE -> TODO returns 400 Bad Request")
        void shouldReturn400ForDoneToTodo() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC9");
            long taskId = created.get("id").asLong();

            // Chain to DONE: TODO -> IN_PROGRESS -> DONE
            transitionStatusExpect200(taskId, "IN_PROGRESS");
            transitionStatusExpect200(taskId, "DONE");

            MvcResult result = transitionStatus(taskId, "TODO");

            assertThat(result.getResponse().getStatus()).isEqualTo(400);
        }

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status with DONE -> IN_PROGRESS returns 400 Bad Request")
        void shouldReturn400ForDoneToInProgress() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC9 extra");
            long taskId = created.get("id").asLong();

            transitionStatusExpect200(taskId, "IN_PROGRESS");
            transitionStatusExpect200(taskId, "DONE");

            MvcResult result = transitionStatus(taskId, "IN_PROGRESS");

            assertThat(result.getResponse().getStatus()).isEqualTo(400);
        }
    }

    // ── AC10: Successful transition updates updatedAt ───────────────────

    @Nested
    @DisplayName("AC10: Successful transition updates updatedAt")
    class AC10_UpdatedAtChanges {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status on successful transition sets updatedAt to server time")
        void shouldUpdateUpdatedAtOnSuccessfulTransition() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC10");
            long taskId = created.get("id").asLong();

            // The task may have null updatedAt initially (only createdAt is set on creation)
            JsonNode response = transitionStatusExpect200(taskId, "IN_PROGRESS");

            // updatedAt should now be non-null
            assertThat(response.get("updatedAt")).isNotNull();
            assertThat(response.get("updatedAt").isNull()).isFalse();
            assertThat(response.get("updatedAt").asText()).isNotEmpty();
        }

        @Test
        @DisplayName("updatedAt changes on each subsequent transition")
        void shouldChangeUpdatedAtOnEachTransition() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC10b");
            long taskId = created.get("id").asLong();

            // Transition 1: TODO -> IN_PROGRESS
            JsonNode first = transitionStatusExpect200(taskId, "IN_PROGRESS");
            String updatedAt1 = first.get("updatedAt").asText();
            assertThat(updatedAt1).isNotEmpty();

            // Small pause to ensure different timestamp
            Thread.sleep(10);

            // Transition 2: IN_PROGRESS -> DONE
            JsonNode second = transitionStatusExpect200(taskId, "DONE");
            String updatedAt2 = second.get("updatedAt").asText();
            assertThat(updatedAt2).isNotEmpty();

            // updatedAt should have changed (or at least be present)
            // Due to fast execution, they might be the same millisecond,
            // so we just verify both are non-null
            assertThat(updatedAt1).isNotNull();
            assertThat(updatedAt2).isNotNull();
        }
    }

    // ── AC11: GET transitions for TODO -> ["IN_PROGRESS"] ───────────────

    @Nested
    @DisplayName("AC11: GET transitions for TODO returns [IN_PROGRESS]")
    class AC11_TransitionsForTodo {

        @Test
        @DisplayName("GET /api/tasks/{id}/transitions for TODO task returns currentStatus=TODO and availableTransitions=[IN_PROGRESS]")
        void shouldReturnInProgressTransitionForTodo() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC11");
            long taskId = created.get("id").asLong();

            MvcResult result = mockMvc.perform(get("/api/tasks/{id}/transitions", taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(response.get("currentStatus").asText()).isEqualTo("TODO");

            JsonNode transitions = response.get("availableTransitions");
            assertThat(transitions.isArray()).isTrue();
            assertThat(transitions.size()).isEqualTo(1);
            assertThat(transitions.get(0).asText()).isEqualTo("IN_PROGRESS");
        }
    }

    // ── AC12: GET transitions for IN_PROGRESS -> ["TODO", "DONE"] ──────

    @Nested
    @DisplayName("AC12: GET transitions for IN_PROGRESS returns [TODO, DONE]")
    class AC12_TransitionsForInProgress {

        @Test
        @DisplayName("GET /api/tasks/{id}/transitions for IN_PROGRESS task returns [TODO, DONE]")
        void shouldReturnTodoAndDoneTransitionsForInProgress() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC12");
            long taskId = created.get("id").asLong();

            // Move to IN_PROGRESS first
            transitionStatusExpect200(taskId, "IN_PROGRESS");

            MvcResult result = mockMvc.perform(get("/api/tasks/{id}/transitions", taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(response.get("currentStatus").asText()).isEqualTo("IN_PROGRESS");

            JsonNode transitions = response.get("availableTransitions");
            assertThat(transitions.isArray()).isTrue();
            assertThat(transitions.size()).isEqualTo(2);

            // Collect transition values
            java.util.List<String> transitionList = new java.util.ArrayList<>();
            for (int i = 0; i < transitions.size(); i++) {
                transitionList.add(transitions.get(i).asText());
            }
            assertThat(transitionList).containsExactlyInAnyOrder("TODO", "DONE");
        }
    }

    // ── AC13: GET transitions for DONE -> ["CLOSED"] ────────────────────

    @Nested
    @DisplayName("AC13: GET transitions for DONE returns [CLOSED]")
    class AC13_TransitionsForDone {

        @Test
        @DisplayName("GET /api/tasks/{id}/transitions for DONE task returns [CLOSED]")
        void shouldReturnClosedTransitionForDone() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC13");
            long taskId = created.get("id").asLong();

            // Chain: TODO -> IN_PROGRESS -> DONE
            transitionStatusExpect200(taskId, "IN_PROGRESS");
            transitionStatusExpect200(taskId, "DONE");

            MvcResult result = mockMvc.perform(get("/api/tasks/{id}/transitions", taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(response.get("currentStatus").asText()).isEqualTo("DONE");

            JsonNode transitions = response.get("availableTransitions");
            assertThat(transitions.isArray()).isTrue();
            assertThat(transitions.size()).isEqualTo(1);
            assertThat(transitions.get(0).asText()).isEqualTo("CLOSED");
        }
    }

    // ── AC14: GET transitions for CLOSED -> [] ──────────────────────────

    @Nested
    @DisplayName("AC14: GET transitions for CLOSED returns empty array")
    class AC14_TransitionsForClosed {

        @Test
        @DisplayName("GET /api/tasks/{id}/transitions for CLOSED task returns empty availableTransitions")
        void shouldReturnEmptyTransitionsForClosed() throws Exception {
            JsonNode created = createTaskViaApi("Task for AC14");
            long taskId = created.get("id").asLong();

            // Chain: TODO -> IN_PROGRESS -> DONE -> CLOSED
            transitionStatusExpect200(taskId, "IN_PROGRESS");
            transitionStatusExpect200(taskId, "DONE");
            transitionStatusExpect200(taskId, "CLOSED");

            MvcResult result = mockMvc.perform(get("/api/tasks/{id}/transitions", taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(response.get("currentStatus").asText()).isEqualTo("CLOSED");

            JsonNode transitions = response.get("availableTransitions");
            assertThat(transitions.isArray()).isTrue();
            assertThat(transitions.size()).isEqualTo(0);
        }
    }

    // ── AC15: No token -> 401 Unauthorized ──────────────────────────────

    @Nested
    @DisplayName("AC15: Endpoints without token return 401 Unauthorized")
    class AC15_Unauthorized {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status without token returns 401")
        void patchStatusWithoutTokenReturns401() throws Exception {
            String body = "{\"status\":\"IN_PROGRESS\"}";

            mockMvc.perform(patch("/api/tasks/{id}/status", 1L)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("GET /api/tasks/{id}/transitions without token returns 401")
        void getTransitionsWithoutTokenReturns401() throws Exception {
            mockMvc.perform(get("/api/tasks/{id}/transitions", 1L))
                    .andExpect(status().isUnauthorized());
        }
    }

    // ── AC16: Non-existent task -> 404 ──────────────────────────────────

    @Nested
    @DisplayName("AC16: Non-existent task returns 404")
    class AC16_NotFound {

        @Test
        @DisplayName("PATCH /api/tasks/{id}/status for non-existent task returns 404")
        void patchStatusForNonExistentTaskReturns404() throws Exception {
            String body = "{\"status\":\"IN_PROGRESS\"}";

            mockMvc.perform(patch("/api/tasks/{id}/status", 99999L)
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isNotFound());
        }

        @Test
        @DisplayName("GET /api/tasks/{id}/transitions for non-existent task returns 404")
        void getTransitionsForNonExistentTaskReturns404() throws Exception {
            mockMvc.perform(get("/api/tasks/{id}/transitions", 99999L)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNotFound());
        }
    }

    // ── Additional: Full lifecycle chain ─────────────────────────────────

    @Nested
    @DisplayName("Additional: Full lifecycle transition chain")
    class FullLifecycle {

        @Test
        @DisplayName("Full chain TODO -> IN_PROGRESS -> DONE -> CLOSED succeeds")
        void shouldCompleteFullLifecycleChain() throws Exception {
            JsonNode created = createTaskViaApi("Full Lifecycle Task");
            long taskId = created.get("id").asLong();
            assertThat(created.get("status").asText()).isEqualTo("TODO");

            JsonNode step1 = transitionStatusExpect200(taskId, "IN_PROGRESS");
            assertThat(step1.get("status").asText()).isEqualTo("IN_PROGRESS");

            JsonNode step2 = transitionStatusExpect200(taskId, "DONE");
            assertThat(step2.get("status").asText()).isEqualTo("DONE");

            JsonNode step3 = transitionStatusExpect200(taskId, "CLOSED");
            assertThat(step3.get("status").asText()).isEqualTo("CLOSED");
        }

        @Test
        @DisplayName("Transition does not change other task fields (title, description, priority)")
        void transitionShouldNotChangeOtherFields() throws Exception {
            JsonNode created = createTaskViaApi("Unchanged Title");
            long taskId = created.get("id").asLong();
            String originalTitle = created.get("title").asText();
            String originalDescription = created.get("description").asText();
            String originalPriority = created.get("priority").asText();

            JsonNode afterTransition = transitionStatusExpect200(taskId, "IN_PROGRESS");

            assertThat(afterTransition.get("title").asText()).isEqualTo(originalTitle);
            assertThat(afterTransition.get("description").asText()).isEqualTo(originalDescription);
            assertThat(afterTransition.get("priority").asText()).isEqualTo(originalPriority);
            assertThat(afterTransition.get("createdBy").asLong()).isEqualTo(testUserId);
        }
    }

    // ── Additional: Error response format for invalid transitions ────────

    @Nested
    @DisplayName("Additional: Error response format for invalid transitions")
    class ErrorResponseFormat {

        @Test
        @DisplayName("400 error response for invalid transition contains status and message fields")
        void shouldReturn400WithProperErrorFormat() throws Exception {
            JsonNode created = createTaskViaApi("Task for error format");
            long taskId = created.get("id").asLong();

            // Attempt illegal transition: TODO -> DONE
            MvcResult result = transitionStatus(taskId, "DONE");

            assertThat(result.getResponse().getStatus()).isEqualTo(400);

            JsonNode errorResponse = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(errorResponse.has("status")).isTrue();
            assertThat(errorResponse.get("status").asInt()).isEqualTo(400);
            assertThat(errorResponse.has("message")).isTrue();
            assertThat(errorResponse.get("message").asText()).isNotEmpty();
        }
    }

    // ── Additional: Self-transition (same status) should fail ────────────

    @Nested
    @DisplayName("Additional: Self-transition returns 400")
    class SelfTransition {

        @Test
        @DisplayName("PATCH TODO -> TODO (self-transition) returns 400")
        void shouldReturn400ForTodoToTodo() throws Exception {
            JsonNode created = createTaskViaApi("Self-transition task");
            long taskId = created.get("id").asLong();

            MvcResult result = transitionStatus(taskId, "TODO");

            assertThat(result.getResponse().getStatus()).isEqualTo(400);
        }
    }
}

